    "overall_confidence": "high",
    "missing_critical_elements": [
      "multicenter status"
    ],
    "extraction_notes": "Primary endpoint is cosmetic scoring, mapped to quality_of_life. Study is single‑arm prospective noninferiority phase 2 trial; multicenter information not provided."
  }
}

